import { AttachInternals, Component, Element, Event, EventEmitter, h, Host, Method, Prop, State, Watch } from '@stencil/core';
import { generateRandId } from '../../utils/utils';
import { DualTextFieldRequirementIndicator } from './wdpr-dual-text-field.model';

@Component({
  tag: 'wdpr-dual-text-field',
  styleUrl: 'wdpr-dual-text-field.css',
  scoped: true,
  formAssociated: true,
})
export class WdprDualTextField {
  /**
   * Reference to the native leading `<input>` element.
   */
  private _leadingInputEl?: HTMLInputElement;

  /**
   * Reference to the native trailing `<input>` element.
   */
  private _trailingInputlEl?: HTMLInputElement;

  private _leadingIconButton?: HTMLSlotElement | null;
  private _trailingIconButton?: HTMLSlotElement | null;

  /**
   * Reference to host element
   * @type {HTMLWdprDualTextFieldElement}
   */
  @Element() el: HTMLWdprDualTextFieldElement;

  @AttachInternals() internals: ElementInternals;

  @State() _internalLeadingInputId: string;
  @State() _internalTrailingInputId: string;
  @State() _leadingFocused = false;
  @State() _trailingFocused = false;

  /**
   * A unique ID for the component. It is essential for accessibility,
   * as it connects the `<label>` to the `<input>` control.
   * If not provided, a random ID will be generated.
   * @type {string}
   */
  @Prop() leadingInputId: string;
  @Prop({ mutable: true }) leadingValue?: string;
  @Prop() leadingLabel: string = 'Leading Label';
  @Prop() leadingRequirementIndicator: DualTextFieldRequirementIndicator = 'none';

  /**
   * A unique ID for the component. It is essential for accessibility,
   * as it connects the `<label>` to the `<input>` control.
   * If not provided, a random ID will be generated.
   * @type {string}
   */
  @Prop() trailingInputId: string;
  @Prop({ mutable: true }) trailingValue?: string;
  @Prop() trailingLabel: string = 'Trailing Label';
  @Prop() trailingRequirementIndicator: DualTextFieldRequirementIndicator = 'none';

  @Prop() helperText: string;
  @Prop() error: boolean = false;
  @Prop() disabled: boolean = false;
  @Prop() required: boolean = false;
  @Prop() leadingName?: string;
  @Prop() trailingName?: string;
  @Prop() readonly: boolean = false;

  @Prop({ attribute: 'a11y-role' }) a11yRole?: 'button' | 'checkbox' | 'combobox' | 'listbox' | 'menu' | 'menubar' | 'option' | 'radio' | 'searchbox' | 'textbox' | string;
  @Prop({ attribute: 'a11y-has-popup' }) a11yHasPopup?: 'false' | 'true' | 'menu' | 'listbox' | 'tree' | 'grid' | 'dialog';
  @Prop({ attribute: 'a11y-controls' }) a11yControls?: string;
  @Prop({ attribute: 'a11y-expanded' }) a11yExpanded?: 'true' | 'false';
  @Prop({ attribute: 'a11y-auto-complete' }) a11yAutoComplete?: 'none' | 'inline' | 'list' | 'both';
  @Prop({ attribute: 'a11y-active-descendant' }) a11yActiveDescendant?: string;
  @Prop({ attribute: 'a11y-disabled' }) a11yDisabled?: 'true' | 'false';
  @Prop({ attribute: 'a11y-required' }) a11yRequired?: 'true' | 'false';
  @Prop({ attribute: 'a11y-described-by' }) a11yDescribedBy?: string;

  /**
   * Event emitted when the input changes.
   */
  @Event() wdprValueChanged: EventEmitter<{ leadingValue?: string; trailingValue?: string }>;

  /**
   * Event emitted when the input gains focus.
   */
  @Event() wdprInputFocus: EventEmitter<unknown>;

  /**
   * Event emitted when the input loses focus.
   */
  @Event() wdprInputBlur: EventEmitter<void>;

  /**
   * Event emitted when any input is clicked.
   * The `field` property indicates which input triggered the click: `'leading'` or `'trailing'`.
   */
  @Event() wdprInputClick: EventEmitter<{ field: 'leading' | 'trailing' }>;

  /**
   * Event emitted when the trailing icon is clicked
   */
  @Event() wdprLeadingIconClick: EventEmitter<void>;

  /**
   * Event emitted when the trailing icon is clicked
   */
  @Event() wdprTrailingIconClick: EventEmitter<void>;

  /**
   * Sets focus on the native `<input>` element.
   * Usage: dualTextField.setLeadingFocus();
   */
  @Method()
  async setLeadingFocus() {
    this._leadingInputEl?.focus();
  }

  /**
   * Sets focus on the native `<input>` element.
   * Usage: dualTextField.setTrailingFocus();
   */
  @Method()
  async setTrailingFocus() {
    this._trailingInputlEl?.focus();
  }

  @Watch('disabled')
  updateDisabledState() {
    this._updateButtonsDisabledState();
    this._updateFormValue();
  }

  @Watch('leadingValue')
  @Watch('trailingValue')
  @Watch('leadingName')
  @Watch('trailingName')
  @Watch('required')
  formPropsChanged() {
    this._updateFormValue();
  }

  componentWillLoad() {
    this._internalLeadingInputId = this.leadingInputId || `wdpr-dual-text-input-${generateRandId()}`;
    this._internalTrailingInputId = this.trailingInputId || `wdpr-dual-text-input-${generateRandId()}`;
    this._leadingIconButton = this.el.querySelector('[slot="leading-icon-button"]');
    this._trailingIconButton = this.el.querySelector('[slot="trailing-icon-button"]');
    this._updateFormValue();
  }

  private _updateButtonsDisabledState = () => {
    const isDisabled = !!this.disabled;

    if (isDisabled) {
      this._leadingIconButton?.setAttribute('disabled', 'true');
      this._trailingIconButton?.setAttribute('disabled', 'true');
    } else {
      this._leadingIconButton?.removeAttribute('disabled');
      this._trailingIconButton?.removeAttribute('disabled');
    }
  };

  private _handleLeadingInput = (event: Event) => {
    const value = (event.target as HTMLInputElement).value;
    this.leadingValue = value;

    this._emitChange();
    this._updateFormValue();
  };

  private _handleTrailingInput = (event: Event) => {
    const value = (event.target as HTMLInputElement).value;
    this.trailingValue = value;

    this._emitChange();
    this._updateFormValue();
  };

  private _updateFormValue() {
    const payload = new FormData();
    const leading = this.leadingValue || '';
    const trailing = this.trailingValue || '';

    if (this.leadingName && leading) payload.append(this.leadingName, leading);
    if (this.trailingName && trailing) payload.append(this.trailingName, trailing);

    const hasAny = !!(this.leadingName && leading) || !!(this.trailingName && trailing);
    const shouldSubmit = !this.disabled && hasAny;

    this.internals?.setFormValue?.(shouldSubmit ? payload : null);
    this._updateValidity(leading, trailing);
  }

  private _updateValidity(leading: string, trailing: string) {
    if (this.disabled) {
      this.internals?.setValidity?.({});

      return;
    }
    if (this.required && (!leading || !trailing)) {
      this.internals?.setValidity?.({ valueMissing: true }, 'Both fields are required');

      return;
    }
    this.internals?.setValidity?.({});
  }

  private _emitChange = () => {
    this.wdprValueChanged.emit({ leadingValue: this.leadingValue, trailingValue: this.trailingValue });
  };

  private _handleLeadingInputClick = () => {
    this.wdprInputClick.emit({ field: 'leading' });
  };

  private _handleTrailingInputClick = () => {
    this.wdprInputClick.emit({ field: 'trailing' });
  };

  private _handleLeadingFocus = (event: FocusEvent) => {
    this._leadingFocused = true;
    this.wdprInputFocus.emit(event);
  };

  private _onLeadingClick = () => {
    this.wdprLeadingIconClick.emit();
  };

  private _handleLeadingBlur = () => {
    this._leadingFocused = false;
    setTimeout(() => {
      if (!this._leadingFocused && !this._trailingFocused) {
        this.wdprInputBlur.emit();
      }
    }, 0);
  };

  private _handleTrailingClick = () => {
    this.wdprTrailingIconClick.emit();
  };

  private _handleTrailingFocus = (event: FocusEvent) => {
    this._trailingFocused = true;
    this.wdprInputFocus.emit(event);
  };

  private _handleTrailingBlur = () => {
    this._trailingFocused = false;
    setTimeout(() => {
      if (!this._leadingFocused && !this._trailingFocused) {
        this.wdprInputBlur.emit();
      }
    }, 0);
  };

  private _handleSlotChange = () => {
    this._updateButtonsDisabledState();
  };

  private _requirementLabel(requirement: DualTextFieldRequirementIndicator): HTMLElement | null {
    if (requirement === 'required') return <span aria-hidden="true"> *</span>;

    if (requirement === 'optional') return <span> (Optional)</span>;

    return null;
  }

  render() {
    return (
      <Host aria-disabled={this.disabled ? 'true' : 'false'}>
        <div class="dual-text-field-wrapper">
          {this._leadingIconButton && (
            <span onClick={this._onLeadingClick} part="leading-icon-button-wrapper">
              {/* Although this is an open slot, the expected usage is to place an wdpr-icon-button here. */}
              <slot name="leading-icon-button" onSlotchange={this._handleSlotChange} />
            </span>
          )}

          <div class="input-wrapper" part="input-wrapper">
            <input
              ref={el => (this._leadingInputEl = el as HTMLInputElement)}
              type="text"
              id={this._internalLeadingInputId}
              placeholder=" "
              class="input"
              disabled={this.disabled}
              value={this.readonly && !this.leadingValue ? '--' : this.leadingValue}
              readonly={this.readonly}
              role={this.a11yRole}
              aria-haspopup={this.a11yHasPopup}
              aria-controls={this.a11yControls}
              aria-expanded={this.a11yExpanded}
              aria-autocomplete={this.a11yAutoComplete}
              aria-activedescendant={this._leadingFocused ? this.a11yActiveDescendant : undefined}
              aria-required={this.a11yRequired}
              aria-invalid={this.error.toString()}
              onFocus={this._handleLeadingFocus}
              onInput={this._handleLeadingInput}
              onClick={this._handleLeadingInputClick}
              onBlur={this._handleLeadingBlur}
              part="input"
            />

            <label htmlFor={this._internalLeadingInputId} class="input-label">
              {this.leadingLabel}{this._requirementLabel(this.leadingRequirementIndicator)}
            </label>
          </div>

          <div class="divider-wrapper">
            <wdpr-divider orientation="vertical" />
          </div>

          <div class="input-wrapper" part="input-wrapper">
            <input
              ref={el => (this._trailingInputlEl = el as HTMLInputElement)}
              type="text"
              id={this._internalTrailingInputId}
              placeholder=" "
              class="input"
              value={this.readonly && !this.trailingValue ? '--' : this.trailingValue}
              disabled={this.disabled}
              readonly={this.readonly}
              role={this.a11yRole}
              aria-haspopup={this.a11yHasPopup}
              aria-controls={this.a11yControls}
              aria-expanded={this.a11yExpanded}
              aria-autocomplete={this.a11yAutoComplete}
              aria-activedescendant={this._trailingFocused ? this.a11yActiveDescendant : undefined}
              aria-required={this.a11yRequired}
              aria-invalid={this.error.toString()}
              onFocus={this._handleTrailingFocus}
              onInput={this._handleTrailingInput}
              onClick={this._handleTrailingInputClick}
              onBlur={this._handleTrailingBlur}
              part="input"
            />

            <label htmlFor={this._internalTrailingInputId} class="input-label">
              {this.trailingLabel}{this._requirementLabel(this.trailingRequirementIndicator)}
            </label>
          </div>

          {this._trailingIconButton && (
            <span onClick={this._handleTrailingClick} part="trailing-icon-button-wrapper">
              {/* Although this is an open slot, the expected usage is to place an wdpr-icon-button here. */}
              <slot name="trailing-icon-button" onSlotchange={this._handleSlotChange} />
            </span>
          )}
        </div>

        {this.helperText && (
          <div class="inline-message-wrapper" part="helper-text-wrapper">
            <wdpr-inline-message variant={this.error ? 'error' : 'informational'} size="small" role="status">{this.helperText}</wdpr-inline-message>
          </div>
        )}
      </Host>
    );
  }
}
